import { useState } from "react";

const App = () => {
  const [selected, setSelected] = useState({});
  const [result, setResult] = useState(null);

  const questions = [
    {
      id: 1,
      question: "Which sensor is used to measure sound intensity in decibels (dB)?",
      options: ["PIR Sensor", "Analog SPL Meter", "LDR", "DHT11"]
    },
    {
      id: 2,
      question: "Which technology detects stationary presence via micro-movements?",
      options: ["Ultrasonic", "Passive Infrared", "mmWave Radar", "Photoresistor"]
    }
  ];

  const handleSelect = (qid, opt) => {
    setSelected((prev) => ({ ...prev, [qid]: opt }));
  };

  const handleSubmit = async () => {
    try {
      const res = await fetch("http://localhost:3000/api/quiz/submit", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          answers: selected
        })
      });

      const data = await res.json();

      setResult(data); // ✅ FIXED
    } catch (err) {
      console.error("Error submitting quiz:", err);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.wrapper}>

        {/* HEADER */}
        <header style={styles.header}>
          <div>
            <h1 style={styles.logo}>
              QUIZZLY <span style={styles.vTag}>V3</span>
            </h1>
            <div style={styles.glowBar} />
          </div>
          <div style={styles.userInfo}>
            <p style={styles.userName}>Harshith B</p>
            <p style={styles.userId}>23MIS0012</p>
          </div>
        </header>

        {/* QUIZ */}
        <div style={styles.quizArea}>
          {questions.map((q) => (
            <div key={q.id} style={styles.qCard}>
              <h2 style={styles.qTitle}>
                <span style={styles.qNum}>{q.id.toString().padStart(2, '0')}</span> 
                {q.question}
              </h2>

              <div style={styles.optGrid}>
                {q.options.map((opt) => {
                  const isActive = selected[q.id] === opt;
                  return (
                    <button
                      key={opt}
                      onClick={() => handleSelect(q.id, opt)}
                      style={{ ...styles.optBtn, ...(isActive ? styles.optActive : {}) }}
                    >
                      <div style={{ ...styles.dot, borderColor: isActive ? "#818cf8" : "#334155" }}>
                        {isActive && <div style={styles.dotInner} />}
                      </div>
                      {opt}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

        {/* SUBMIT */}
        <footer style={styles.footer}>
          <button onClick={handleSubmit} style={styles.submitBtn}>
            Finish Attempt
          </button>
        </footer>

        {/* 🔥 RESULT DISPLAY (V3 MAIN PART) */}
        {result && (
          <div style={styles.resultBox}>
            <h2>Result</h2>
            <p>Score: {result.score} / {result.total}</p>
            <p>Percentage: {result.percentage}%</p>
          </div>
        )}

      </div>
    </div>
  );
};

const styles = {
  container: {
    height: "100vh",
    width: "100vw",
    backgroundColor: "#020617",
    color: "#f1f5f9",
    display: "flex",
    justifyContent: "center"
  },
  wrapper: {
    width: "100%",
    maxWidth: "850px",
    padding: "20px"
  },
  header: {
    display: "flex",
    justifyContent: "space-between"
  },
  logo: { fontSize: "20px", fontWeight: "900" },
  vTag: { color: "#6366f1" },
  glowBar: { height: "3px", width: "30px", background: "#6366f1" },
  userInfo: { textAlign: "right" },
  quizArea: { marginTop: "20px" },
  qCard: {
    marginBottom: "20px",
    padding: "20px",
    background: "#0f172a",
    borderRadius: "12px"
  },
  qTitle: { fontSize: "16px" },
  optGrid: { display: "grid", gridTemplateColumns: "1fr 1fr", gap: "10px" },
  optBtn: {
    padding: "10px",
    border: "1px solid #1e293b",
    borderRadius: "8px",
    cursor: "pointer",
    background: "#020617",
    color: "#94a3b8"
  },
  optActive: {
    borderColor: "#6366f1",
    color: "#fff"
  },
  dot: { marginRight: "10px" },
  dotInner: { width: "6px", height: "6px", background: "#6366f1" },
  footer: { textAlign: "center", marginTop: "20px" },
  submitBtn: {
    padding: "12px 40px",
    background: "#6366f1",
    borderRadius: "10px",
    cursor: "pointer"
  },
  resultBox: {
    marginTop: "20px",
    padding: "20px",
    background: "#0f172a",
    borderRadius: "12px",
    textAlign: "center"
  }
};

export default App;
